#include &lt;stdio.h&gt; #include &lt;stdlib.h&gt; #include &lt;malloc.h&gt; struct student { int num; float score; struct student *next; }; struct student *head, *p, *p1; int n = 0, i; struct student *creat(){ p1 = p = (struct student *)malloc(sizeof(struct student)); scanf_s(&#34;%d%f&#34;, &amp;p-&gt;num,&amp;p-&gt;score); while(p-&gt;num!= NULL){ n++; if(n == 1)head = p; else p1-&gt;next = p; p1 = p; p = (struct student *)malloc(sizeof(struct student)); scanf_s(&#34;%d%f&#34;, &amp;p-&gt;num,&amp;p-&gt;score); } p1-&gt;next = NULL; return head; } void main (){ head=creat(); p = head; for(i = 0; i &lt; n; i++){ printf(&#34;%d%10.2f\n&#34;, p-&gt;num,p-&gt;score); p = p-&gt;next; } system(&#34;pause&#34;); } 同时贴出一位网友给我的另一段代码：
#include &lt;stdio.h&gt; #include &lt;stdlib.h&gt; #include &lt;malloc.h&gt; struct student { int num; float score; struct student *next; }; struct student *creat(){ struct student *p, *curr; int num; float score; struct student *head = (struct student *)malloc(sizeof(struct student)); if(!head) return NULL; head-&gt;next = NULL; curr = head; printf(&#34;Please enter:num(-1 to break) and score\n&#34;); scanf(&#34;%d&#34;, &amp;num); while(num != -1){ scanf(&#34;%f&#34;, &amp;score); p = (struct student *)malloc(sizeof(struct student)); if(!p) return head; p-&gt;num = num; p-&gt;score = score; p-&gt;next = NULL; curr-&gt;next = p; curr = curr-&gt;next; scanf(&#34;%d&#34;, &amp;num); } return head; } int main(){ struct student *head, *p; head = creat(); p = head-&gt;next; while(p){ printf(&#34;%d%10.2f\n&#34;, p-&gt;num,p-&gt;score); p = p-&gt;next; } system(&#34;pause&#34;); return 0; } 他在一些细节上都做了优化，学习学习~
5.对动态链表的操作
1）输出
输出可以参考上面的代码了。
2）删除
删除链表的算法就是输入学号，然后程序要检查是否和已有的结点对应，相等的话把那个结点删掉，不相等的话继续向后扫描，直到相等的时候执行删除的步骤，也就是将p2-&gt;next的结点赋值给p1-&gt;next而不是p1。如果要删除的是第一个结点，则使p1-&gt;head，如果扫描到最后还没有相等的结点，结束程序。
struct student *del(struct student *head,int num){ if (head==NULL){ printf(&#34;链表为空链表&#34;); return head; } p1=head; while (num!=p1-&gt;num&amp;&amp;p1-&gt;num!=NULL){ p2=p1; p1=p1-&gt;next; } if(num==p1-&gt;num){ if (p1==head)head=p1-&gt;next; else p2-&gt;next=p1-&gt;next; } return (head); } 3）插入
插入链表的算法：p0为要插入的结点的指针，将p2-&gt;next的值赋给p0，将p0-&gt;next的值赋给p1，改变原来p2-&gt;next=p1的情况即多出了一个新的结点。
struct student *insert (struct student *head,struct student *stu){ struct student *p0; p0=stu; if (head==NULL){ head=p0; p0-&gt;next=NULL; } else {	while ((p0-&gt;num&gt;p1-&gt;num)&amp;&amp;(p1-&gt;next!=NULL)){	p2=p1; p1=p1-&gt;next; } if (p0-&gt;num&lt;=p1-&gt;num){ if (head=p1)head=p0; else p2-&gt;next=p0;	p0-&gt;next=p1; } else{ p1-&gt;next=p0; p0-&gt;next=NULL; } } return(head); }
